/**
 * Splash Screen Module
 *
 * Displays an informative splash screen during system warmup (first visit only).
 * Shows system highlights, component loading progress, and links to full infographics.
 */

const SPLASH_STORAGE_KEY = 'searchatSplashDismissedServerStartedAt';
const LEGACY_SPLASH_STORAGE_KEY = 'searchatSplashShown';
const STATUS_POLL_INTERVAL = 500; // ms
const CRITICAL_COMPONENTS = ['embedder', 'faiss', 'metadata'];

// 8-12 key highlights with icons (medium summary)
const HIGHLIGHTS = [
    { icon: '🔍', title: '3 Search Modes', desc: 'Hybrid (DuckDB FTS + FAISS), Semantic, Keyword' },
    { icon: '⚡', title: '<100ms Search', desc: 'Ultra-fast hybrid search with RRF fusion' },
    { icon: '🎯', title: 'Smart Matching', desc: 'Autocomplete, synonym expansion, cross-encoder re-ranking' },
    { icon: '🤖', title: '8 AI Agents', desc: 'Claude, Vibe, OpenCode, Codex, Gemini, Continue, Cursor, Aider' },
    { icon: '🔌', title: 'MCP Server', desc: '8 tools for MCP clients (search, patterns, agent config)' },
    { icon: '💬', title: 'Session Chat', desc: 'Multi-turn RAG with 30-min session persistence' },
    { icon: '🧩', title: 'Pattern Mining', desc: 'Extract recurring coding patterns via LLM' },
    { icon: '📋', title: 'Agent Config', desc: 'Generate CLAUDE.md, copilot-instructions, cursorrules' },
    { icon: '🔗', title: 'Similarity Search', desc: 'Discover related conversations' },
    { icon: '🔖', title: 'Bookmarks', desc: 'Save and annotate favorites' },
    { icon: '📊', title: 'Analytics', desc: 'Track search patterns and trends' },
    { icon: '🛡️', title: 'Append-Only', desc: 'Never deletes existing data' },
    { icon: '📈', title: '55+ API Endpoints', desc: 'Comprehensive REST API with 14 routers' },
];

let pollInterval = null;
let _currentServerStartedAt = null;
let _sidebarPollInterval = null;
let _warmupStartedAt = null;
let _warmupUIActive = false;

const WARMUP_MAX_DURATION_MS = 120_000; // 2 minutes
const SIDEBAR_POLL_MAX_FAILURES = 20;   // 10 seconds at 500ms

function areCriticalComponentsReady(status) {
    return CRITICAL_COMPONENTS.every(
        name => status?.components?.[name] === 'ready'
    );
}

/**
 * Check if user has seen splash before
 */
function hasDismissedSplashForServer(serverStartedAt) {
    if (!serverStartedAt) return false;
    try {
        return localStorage.getItem(SPLASH_STORAGE_KEY) === String(serverStartedAt);
    } catch (error) {
        console.warn('Splash: failed to read localStorage', error);
        return false;
    }
}

/**
 * Mark splash as seen (persistent across sessions)
 */
function markSplashDismissedForServer(serverStartedAt) {
    if (!serverStartedAt) return;
    try {
        localStorage.setItem(SPLASH_STORAGE_KEY, String(serverStartedAt));
    } catch (error) {
        console.warn('Splash: failed to write localStorage', error);
    }
}

function clearLegacySplashFlag() {
    try {
        localStorage.removeItem(LEGACY_SPLASH_STORAGE_KEY);
    } catch (error) {
        console.warn('Splash: failed to clear legacy localStorage key', error);
    }
}

/**
 * Returns true when the sidebar warmup indicator is active
 * (splash was dismissed before critical components finished loading).
 * Includes a safety valve: expires after WARMUP_MAX_DURATION_MS to
 * prevent permanently blocking search/chat.
 */
export function isWarmingUp() {
    const indicator = document.getElementById('sidebarWarmupIndicator');
    if (!indicator) return false;

    const visible = getComputedStyle(indicator).display !== 'none';
    if (!visible) {
        _warmupStartedAt = null;
        return false;
    }

    if (_warmupStartedAt === null) _warmupStartedAt = Date.now();
    if (Date.now() - _warmupStartedAt > WARMUP_MAX_DURATION_MS) {
        console.warn('isWarmingUp: warmup exceeded maximum duration, unblocking search/chat');
        indicator.style.display = 'none';
        _warmupStartedAt = null;
        return false;
    }

    return true;
}

/**
 * Enable or disable interactive UI elements during warmup.
 * When warming=true: search input disabled, chat link inert.
 * When warming=false: everything restored.
 */
export function setWarmupUI(warming) {
    if (warming === _warmupUIActive) return;
    _warmupUIActive = warming;

    const searchInput = document.getElementById('search');
    const searchWrap = document.querySelector('.search-wrap');
    const chatLink = document.getElementById('chatNavLink');

    if (searchInput) {
        searchInput.disabled = warming;
    }
    if (searchWrap) {
        searchWrap.classList.toggle('warming-up', warming);
    }
    if (chatLink) {
        if (warming) {
            chatLink.dataset.href = chatLink.getAttribute('href');
            chatLink.removeAttribute('href');
            chatLink.setAttribute('aria-disabled', 'true');
            chatLink.style.pointerEvents = 'none';
            chatLink.style.opacity = '0.5';
        } else {
            const savedHref = chatLink.dataset.href;
            if (savedHref) {
                chatLink.setAttribute('href', savedHref);
                delete chatLink.dataset.href;
            }
            chatLink.removeAttribute('aria-disabled');
            chatLink.style.pointerEvents = '';
            chatLink.style.opacity = '';
        }
    }
}

/**
 * Check warmup status and show splash if needed (first visit only)
 */
export async function checkAndShowSplash() {
    try {
        clearLegacySplashFlag();

        const response = await fetch('/api/status');
        const status = await response.json();

        const serverStartedAt = status.server_started_at || status.warmup_started_at;
        _currentServerStartedAt = serverStartedAt || null;
        const criticalReady = areCriticalComponentsReady(status);

        // If the critical components are already ready, skip the blocking
        // splash entirely and remember that this server start is already usable.
        if (criticalReady) {
            markSplashDismissedForServer(_currentServerStartedAt);
            setWarmupUI(false);
            return;
        }

        // Show splash once per server start when warmup is still in progress.
        if (hasDismissedSplashForServer(_currentServerStartedAt)) {
            return;
        }

        setWarmupUI(true);
        renderSplash(status);
        pollWarmupStatus();
    } catch (error) {
        console.error('Failed to check warmup status:', error);
    }
}

/**
 * Render splash overlay with highlights and progress
 */
function renderSplash(status) {
    // Create overlay
    const overlay = document.createElement('div');
    overlay.id = 'splashOverlay';
    overlay.className = 'splash-overlay';

    // Create content card
    const content = document.createElement('div');
    content.className = 'splash-content';

    // Header
    const header = document.createElement('div');
    header.className = 'splash-header';
    header.innerHTML = `
        <h1><span class="text-shimmer">searchat</span></h1>
        <p>Warming up search engine...</p>
    `;
    content.appendChild(header);

    // Highlights grid
    const highlightsContainer = document.createElement('div');
    highlightsContainer.className = 'splash-highlights';
    HIGHLIGHTS.forEach(highlight => {
        const item = document.createElement('div');
        item.className = 'splash-highlight-item stat-card';
        item.innerHTML = `
            <span class="splash-highlight-icon">${highlight.icon}</span>
            <div class="splash-highlight-text">
                <div class="splash-highlight-title">${highlight.title}</div>
                <div class="splash-highlight-desc">${highlight.desc}</div>
            </div>
        `;
        highlightsContainer.appendChild(item);
    });
    content.appendChild(highlightsContainer);

    // Progress container
    const progressContainer = document.createElement('div');
    progressContainer.id = 'splashProgress';
    progressContainer.className = 'splash-progress-container';
    content.appendChild(progressContainer);

    // Actions
    const actions = document.createElement('div');
    actions.className = 'splash-actions';
    actions.innerHTML = `
        <a href="/docs/infographics.html" target="_blank" class="splash-btn splash-btn-secondary">
            View Full Infographics
        </a>
        <button id="splashDismiss" class="splash-btn splash-btn-primary">
            Get Started
        </button>
    `;
    content.appendChild(actions);

    overlay.appendChild(content);
    document.body.appendChild(overlay);

    // Manual dismiss (always required; never auto-dismiss)
    const dismissBtn = document.getElementById('splashDismiss');
    if (dismissBtn) {
        dismissBtn.onclick = dismissSplash;
    }

    // Initial progress render
    updateProgress(status);

    // Fade in animation
    setTimeout(() => overlay.classList.add('splash-visible'), 10);
}

/**
 * Update progress indicators based on status
 */
function updateProgress(status) {
    const container = document.getElementById('splashProgress');
    if (!container) return;

    // Clear existing progress items
    container.innerHTML = '';

    // Component display order (prioritize critical ones)
    const componentOrder = [
        'services',
        'duckdb',
        'parquet',
        'search_engine',
        'embedder',
        'embedded_model',
        'faiss',
        'metadata',
        'indexer'
    ];

    componentOrder.forEach(name => {
        const state = status.components[name];
        if (!state) return;

        const item = renderProgressItem(name, state, status.errors[name]);
        container.appendChild(item);
    });
}

/**
 * Render individual progress item with spinner and bar
 */
function renderProgressItem(name, state, detail) {
    const item = document.createElement('div');
    item.className = 'splash-progress-item';

    // Component icon based on state
    let icon = '';
    if (state === 'ready') {
        icon = '✓';
    } else if (state === 'error') {
        icon = '✗';
    } else {
        icon = '⏳';
    }

    // Progress percentage based on state
    let progress = 0;
    let statusText = '';
    if (state === 'ready') {
        progress = 100;
        statusText = 'Ready';
    } else if (state === 'loading') {
        progress = 60;
        statusText = detail || 'Loading...';
    } else if (state === 'error') {
        progress = 0;
        statusText = detail || 'Error';
    } else {
        progress = 0;
        if (name === 'embedded_model') {
            statusText = detail || 'Not enabled';
        } else {
            statusText = detail || 'Idle';
        }
    }

    // Spinner only for active loading.
    const showSpinner = state === 'loading';
    const spinnerHtml = showSpinner
        ? '<div class="splash-spinner" aria-hidden="true"></div>'
        : '';

    item.innerHTML = `
        <span class="splash-progress-icon">${icon}</span>
        <span class="splash-progress-name">${formatComponentName(name)}</span>
        ${spinnerHtml}
        <div class="splash-progress-bar">
            <div class="splash-progress-fill" style="width: ${progress}%"></div>
        </div>
        <span class="splash-progress-status">${statusText}</span>
    `;

    // Add state class for styling
    item.classList.add(`splash-progress-${state}`);

    return item;
}

/**
 * Format component name for display
 */
function formatComponentName(name) {
    const names = {
        'services': 'Services',
        'duckdb': 'Database',
        'parquet': 'Data Files',
        'search_engine': 'Search Engine',
        'faiss': 'FAISS Index',
        'metadata': 'Metadata',
        'embedder': 'AI Embeddings',
        'embedded_model': 'Embedded LLM',
        'indexer': 'Indexer'
    };
    return names[name] || name;
}

/**
 * Poll warmup status until ready or error
 */
function pollWarmupStatus() {
    if (pollInterval) {
        clearInterval(pollInterval);
    }

    pollInterval = setInterval(async () => {
        try {
            const response = await fetch('/api/status');
            const status = await response.json();

            // Update progress display
            updateProgress(status);

            const criticalReady = areCriticalComponentsReady(status);

            // Once ready, stop polling to reduce overhead. Overlay stays until user dismisses.
            if (criticalReady && pollInterval) {
                clearInterval(pollInterval);
                pollInterval = null;
            }
        } catch (error) {
            console.error('Failed to poll status:', error);
        }
    }, STATUS_POLL_INTERVAL);
}

/**
 * Dismiss splash screen and mark as seen.
 * If critical components are still loading, show a sidebar warmup indicator.
 */
async function dismissSplash() {
    markSplashDismissedForServer(_currentServerStartedAt);

    // Check if critical components are ready before tearing down polling
    let criticalReady = false;
    try {
        const response = await fetch('/api/status');
        if (!response.ok) throw new Error(`Status API returned ${response.status}`);
        const status = await response.json();
        criticalReady = areCriticalComponentsReady(status);
    } catch (err) {
        console.warn('dismissSplash: status check failed, assuming not ready', err);
    }

    // Stop splash polling
    if (pollInterval) {
        clearInterval(pollInterval);
        pollInterval = null;
    }

    // Fade out and remove overlay
    const overlay = document.getElementById('splashOverlay');
    if (overlay) {
        overlay.classList.remove('splash-visible');
        setTimeout(() => overlay.remove(), 300);
    }

    // If still warming up, show sidebar indicator and continue polling
    if (!criticalReady) {
        showSidebarWarmupIndicator();
    } else {
        setWarmupUI(false);
    }
}

/**
 * Show a spinner above the server status section that polls
 * until all critical components are ready or max failures reached.
 */
function showSidebarWarmupIndicator() {
    if (_sidebarPollInterval) return;

    const indicator = document.getElementById('sidebarWarmupIndicator');
    if (!indicator) {
        console.warn('showSidebarWarmupIndicator: #sidebarWarmupIndicator not found in DOM');
        return;
    }

    indicator.style.display = '';
    let consecutiveFailures = 0;

    _sidebarPollInterval = setInterval(async () => {
        try {
            const response = await fetch('/api/status');
            if (!response.ok) throw new Error(`HTTP ${response.status}`);
            const status = await response.json();

            const ready = areCriticalComponentsReady(status);
            consecutiveFailures = 0;

            if (ready) {
                clearInterval(_sidebarPollInterval);
                _sidebarPollInterval = null;
                indicator.style.display = 'none';
                setWarmupUI(false);
            }
        } catch (err) {
            consecutiveFailures++;
            console.warn('Sidebar warmup poll failed:', err);
            if (consecutiveFailures >= SIDEBAR_POLL_MAX_FAILURES) {
                clearInterval(_sidebarPollInterval);
                _sidebarPollInterval = null;
                const label = indicator.querySelector('.sidebar-warmup-label');
                if (label) label.textContent = 'Warmup check failed \u2014 reload page';
            }
        }
    }, STATUS_POLL_INTERVAL);
}
